/* :root from el-bychudy-nav-00 source */
.el-bychudy-nav-00-root{--ink:#0a0a0a;
      --paper:#f4f1ec;
      --paper-2:#e8e3d8;
      --paper-3:#dcd6c8;
      --accent:#ff2d2d;
